using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 breaking change: Migrate() now manages its own transaction
    // internally. Wrapping it in a user transaction causes an error.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

