// ============================================================================
// EF Core 9 – Cosmos DB Breaking-Change Fixes
// Apply these patterns to your separate Cosmos DB project.
// ============================================================================

using Microsoft.EntityFrameworkCore;

// ---------------------------------------------------------------------------
// BREAKING CHANGE 1 – Discriminator property renamed from "Discriminator" to "$type"
//
// EF Core 9 Cosmos provider now uses "$type" by default. Existing documents
// store the value under "Discriminator", so queries will fail unless you
// explicitly configure the old property name.
// ---------------------------------------------------------------------------
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Preserve the property name used by existing documents.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

// ---------------------------------------------------------------------------
// BREAKING CHANGE 2 – Synchronous I/O on Cosmos DB is no longer supported
//
// EF Core 9 Cosmos provider throws InvalidOperationException on sync calls
// such as ToList(), First(), Single(), Count(), etc.
// All queries must use their async counterparts.
// ---------------------------------------------------------------------------
class CosmosQueryExamples
{
    // ❌ BEFORE (EF Core 8) – sync calls that now throw in EF Core 9:
    //
    //   var products = db.Products.ToList();
    //   var first    = db.Products.First(p => p.Name == "Widget");
    //   var count    = db.Products.Count();

    // ✅ AFTER (EF Core 9) – use async equivalents:
    async Task Examples(CosmosDbContext db)
    {
        var products = await db.Products.ToListAsync();
        var first    = await db.Products.FirstAsync(p => p.Name == "Widget");
        var count    = await db.Products.CountAsync();
    }
}

